import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Porting to 1.21.4","description":"A guide for porting to Minecraft 1.21.4.","frontmatter":{"title":"Porting to 1.21.4","description":"A guide for porting to Minecraft 1.21.4.","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"1.21.4/develop/porting/index.md","filePath":"versions/1.21.4/develop/porting/index.md","lastUpdated":1774372461000}`);var a={name:`1.21.4/develop/porting/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Porting to 1.21.4 <a class="header-anchor" href="#h1" aria-label="Permalink to “Porting to 1.21.4”">​</a></h1><p>Minecraft is a game that&#39;s constantly evolving, with new versions changing the game in ways that affect modders. This article covers the general steps one might follow to update their mod to the 1.21.4 update of Minecraft.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>These docs discuss migrating from <strong>1.21.1</strong> to <strong>1.21.4</strong>. If you&#39;re looking for another migration, switch to the target version by using the dropdown in the top-right corner.</p></div><h2 id="build-script" tabindex="-1">Updating the Build Script <a class="header-anchor" href="#build-script" aria-label="Permalink to “Updating the Build Script”">​</a></h2><p>Start by updating your mod&#39;s <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code>, and <code>build.gradle</code> to the latest versions:</p><ol><li>Update Gradle to the latest version by running the following command: <code>./gradlew wrapper --gradle-version latest</code></li><li>Bump Minecraft, Fabric Loader, Fabric Loom and Fabric API, either in <code>gradle.properties</code> (recommended) or in <code>build.gradle</code>. Find the recommended versions of the Fabric components on the <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop site</a>.</li><li>Refresh Gradle by using the refresh button in the top-right corner of IntelliJ IDEA. If this button is not visible, you can force caches to be cleared by running <code>./gradlew --refresh-dependencies</code>.</li></ol><h2 id="porting-guides" tabindex="-1">Updating the Code <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Updating the Code”">​</a></h2><p>After the build script has been updated to 1.21.4, you can now go through your mod and update any code that has changed to make it compatible with the new version.</p><p>To help you with updating, modders will document the changes they came across in articles, like the Fabric Blog, and NeoForge&#39;s porting primers.</p><ul><li><a href="https://fabricmc.net/2024/12/02/1214.html" target="_blank" rel="noreferrer"><em>Fabric for Minecraft 1.21.4</em> on the Fabric blog</a> contains a high-level explanation of the changes made to Fabric API in 1.21.4.</li><li><a href="https://www.minecraft.net/en-us/article/minecraft-java-edition-1-21-4" target="_blank" rel="noreferrer"><em>Minecraft: Java Edition 1.21.4</em> on the Minecraft blog</a> is the official overview of the features introduced in 1.21.4.</li><li><a href="https://minecraft.wiki/w/Java_Edition_1.21.4" target="_blank" rel="noreferrer"><em>Java Edition 1.21.4</em> on the Minecraft Wiki</a> is an unofficial summary of the contents of the update.</li><li><a href="https://www.youtube.com/watch?v=6K1QzvJx1IE" target="_blank" rel="noreferrer">slicedlime&#39;s Data &amp; Resource Pack News in Minecraft 1.21.4</a> covers information relevant to updating your mod&#39;s data and resource pack driven content.</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/1.21.4/index.md" target="_blank" rel="noreferrer">NeoForge&#39;s <em>Minecraft 1.21.3 -&gt; 1.21.4 Mod Migration Primer</em></a> covers migrating from 1.21.3 to 1.21.4, focusing only on vanilla code changes. <ul><li>Please note that the linked article is third-party material, not maintained by Fabric. It&#39;s under copyright of @ChampionAsh5357, and licensed under <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a>.</li></ul></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};